// src/pages/Login.jsx

import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {

  const nav = useNavigate();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [role, setRole] =
    useState("customer");

  const loginUser = async (e) => {

    e.preventDefault();

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/login",
        {
          email,
          password,
          role
        }
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data.user)
      );

      if (role === "customer") {

        nav("/customer-dashboard");

      } else {

        nav("/labour-dashboard");

      }

    } catch (err) {

      alert("Invalid Credentials");

    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        <div style={styles.logo}>
          D
        </div>

        <h2 style={styles.title}>
          Login
        </h2>

        <p style={styles.subtitle}>
          Welcome back
        </p>

        <form onSubmit={loginUser}>

          <select
            style={styles.input}
            value={role}
            onChange={(e) =>
              setRole(e.target.value)
            }
          >

            <option value="customer">
              Customer
            </option>

            <option value="labour">
              Labour
            </option>

          </select>

          <input
            type="email"
            placeholder="Email"
            style={styles.input}
            value={email}
            onChange={(e) =>
              setEmail(e.target.value)
            }
          />

          <input
            type="password"
            placeholder="Password"
            style={styles.input}
            value={password}
            onChange={(e) =>
              setPassword(e.target.value)
            }
          />

          <button style={styles.button}>
            Login
          </button>

        </form>

        <p style={styles.bottomText}>

          No account?

          <span
            style={styles.link}
            onClick={() =>
              nav("/register")
            }
          >
            Register
          </span>

        </p>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background:
      "linear-gradient(135deg,#0f172a,#1e293b)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial"
  },

  card: {
    width: "340px",
    background: "white",
    padding: "34px",
    borderRadius: "20px",
    boxShadow:
      "0 12px 30px rgba(0,0,0,0.18)"
  },

  logo: {
    width: "52px",
    height: "52px",
    borderRadius: "14px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    margin: "0 auto 18px auto",
    fontSize: "20px",
    fontWeight: "bold"
  },

  title: {
    textAlign: "center",
    margin: 0,
    color: "#111827",
    fontSize: "28px"
  },

  subtitle: {
    textAlign: "center",
    color: "#6b7280",
    marginBottom: "28px",
    marginTop: "8px",
    fontSize: "14px"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "16px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    background: "#f8fafc",
    boxSizing: "border-box",
    fontSize: "14px",
    outline: "none"
  },

  button: {
    width: "100%",
    padding: "14px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold",
    fontSize: "14px",
    marginTop: "4px"
  },

  bottomText: {
    textAlign: "center",
    marginTop: "22px",
    color: "#6b7280",
    fontSize: "14px"
  },

  link: {
    color: "#f97316",
    marginLeft: "5px",
    cursor: "pointer",
    fontWeight: "bold"
  }

};
